import Link from "next/link";
import type { Metadata } from "next";

export const metadata: Metadata = {
  title: "Agendamento Confirmado — Psique",
  description: "Sua sessão foi agendada com sucesso!",
};

export default async function BookingSuccessPage() {
  return (
    <div className="min-h-screen bg-[var(--color-background)] flex flex-col items-center justify-center p-6 md:p-10 relative">
      <div className="max-w-[520px] w-full text-center relative z-10">
        {/* Success animation */}
        <div className="w-20 h-20 rounded-full bg-[var(--color-brand)]/10 border-2 border-[var(--color-brand)]/30 flex items-center justify-center text-[36px] text-[#fbbf24] mx-auto mb-6 animate-[fadeUp_.5s_ease-out_both] shadow-[0_0_30px_rgba(var(--color-brand-rgb),0.15)] relative">
          <div className="absolute inset-0 rounded-full border border-[var(--color-brand)]/50 animate-[ping_2s_cubic-bezier(0,0,0.2,1)_infinite]" />
          <span className="relative z-10 font-[family-name:var(--font-display)]">✓</span>
        </div>

        <h1 className="font-[family-name:var(--font-display)] text-[38px] font-light text-[var(--color-text-primary)] leading-[1.15] mb-3 animate-[fadeUp_.5s_ease-out_.1s_both]">
          Sessão Agendada!
        </h1>

        <p className="text-[15px] text-[var(--color-text-secondary)] leading-[1.7] mb-8 max-w-[460px] mx-auto animate-[fadeUp_.5s_ease-out_.2s_both] font-light">
          Pagamento confirmado com sucesso. Você receberá um email com os
          detalhes da sessão e o link de acesso será enviado 1 hora antes.
        </p>

        <div className="bg-[var(--color-surface)]/50 border border-[var(--color-border-subtle)] rounded-2xl p-6 mb-6 text-left animate-[fadeUp_.5s_ease-out_.3s_both] backdrop-blur-md">
          <h2 className="font-[family-name:var(--font-display)] text-[20px] font-light text-[var(--color-text-primary)] mb-4">
            Próximos passos
          </h2>
          <div className="flex flex-col gap-3">
            {[
              {
                icon: "📧",
                text: "Confira seu email para detalhes do agendamento",
              },
              {
                icon: "🔗",
                text: "O link da videochamada será enviado 1h antes",
              },
              {
                icon: "📱",
                text: "Se tiver Telegram, conecte para lembretes automáticos",
              },
              {
                icon: "🔐",
                text: "Crie sua conta para acessar o Portal do Paciente",
              },
            ].map((step, i) => (
              <div
                key={i}
                className="flex gap-3 items-start text-[14px] text-[var(--color-text-secondary)] leading-[1.5] font-light p-3 rounded-xl hover:bg-[var(--color-surface-hover)]/30 transition-colors"
              >
                <span className="shrink-0 text-[16px]">{step.icon}</span>
                {step.text}
              </div>
            ))}
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 justify-center animate-[fadeUp_.5s_ease-out_.4s_both]">
          <Link
            href="/auth/login"
            className="px-7 py-3 rounded-xl bg-[var(--color-brand)] text-black text-[14px] font-semibold tracking-wide no-underline shadow-[0_4px_24px_rgba(var(--color-brand-rgb),0.25)] hover:shadow-[0_4px_32px_rgba(var(--color-brand-rgb),0.4)] hover:scale-[1.02] transition-all duration-300 w-full sm:w-auto text-center"
          >
            Criar Conta
          </Link>
          <Link
            href="/"
            className="px-7 py-3 rounded-xl bg-[var(--color-surface)] border border-[var(--color-border-subtle)] text-[var(--color-text-secondary)] text-[14px] no-underline hover:bg-[var(--color-surface-hover)] transition-colors w-full sm:w-auto text-center"
          >
            Voltar ao Início
          </Link>
        </div>
      </div>

      {/* Footer */}
      <div className="absolute bottom-6 text-[11px] text-[var(--color-text-muted)] tracking-wide font-light flex items-center justify-center w-full z-10">
        <span className="text-[14px] text-[var(--color-brand)] font-[family-name:var(--font-display)] mr-1.5 leading-none">
          Ψ
        </span>
        Psique — Plataforma Terapêutica
      </div>
    </div>
  );
}
